import machine
import time
from umqtt.simple import MQTTClient

# Set up WiFi and MQTT credentials
WIFI_SSID = 'your_wifi_ssid'
WIFI_PASSWORD = 'your_wifi_password'
MQTT_BROKER_IP = 'your_mqtt_broker_ip'

# Set up sensor pin
SENSOR_PIN = machine.ADC(0)

def connect_to_wifi():
    wlan = machine.WLAN(machine.WLAN.STA)
    wlan.active(True)
    wlan.connect(WIFI_SSID, WIFI_PASSWORD)
    while not wlan.isconnected():
        time.sleep_ms(100)

def get_temperature_reading():
    reading = SENSOR_PIN.read()
    return (reading * 3.3) / 65535

def on_connect(client, userdata, msg, rc):
    if rc == 0:
        print('Connected to MQTT broker')
    else:
        print('Failed to connect to MQTT broker')

def main():
    client_id = 'esp32-sensor'
    mqtt_client = MQTTClient(client_id, MQTT_BROKER_IP)
    
    connect_to_wifi()
    
    while True:
        temperature_reading = get_temperature_reading()
        topic = b'sensors/temp'
        msg = str(temperature_reading).encode('utf-8')
        
        try:
            mqtt_client.connect()
            mqtt_client.publish(topic, msg)
            print(f'Published temperature reading: {temperature_reading}°C')
            time.sleep(10)  # Publish every 10 seconds
        except Exception as e:
            print(f'Error publishing to MQTT broker: {e}')
        
        mqtt_client.disconnect()

if __name__ == '__main__':
    main()